  'persona',
  '{"schema_version":1,"sectionUi":{"atAGlanceTitle":"De un vistazo","atAGlanceSubtitle":"Una lectura rápida sobre paisajes, caminata y encaje del tour.","atmosphereTitle":"Ambiente del recorrido","atmosphereSubtitle":"Antes de los detalles, así se siente el día.","itineraryTitle":"Tu día, parada a parada","itinerarySubtitle":"Cada parada encaja con la siguiente. Amplía para ver todo el detalle.","dayFlowStopsPrefix":"Paradas","stopHighlightsHeading":"Destacados","stopTimeUsedHeading":"Uso del tiempo","stopVisitBasicsHeading":"Lo básico de la visita","stopVisitHoursLabel":"Horario","stopVisitAdmissionLabel":"Entrada","stopVisitWalkingLabel":"Caminata","stopVisitClosedLabel":"Cerrado","stopSmartNotesHeading":"Consejos prácticos","stopSmartNotesPhotoPrefix":"Foto:","stopSmartNotesTipPrefix":"Consejo:","fitTitle":"Por qué encaja este tour","fitSubtitle":"A quiénes va dirigido el ritmo y cómo está repartido el día.","fitBestForLabel":"Ideal para","fitLessIdealLabel":"Menos ideal para","fitFamiliesPrefix":"Familias:","fitFamiliesText":"A partir de 8 años encaja muy bien; con niños más pequeños también es posible, pero la zona del cráter conviene más con niños algo mayores. ","fitSeniorsPrefix":"Mayores:","fitSeniorsText":"En Seongsan, la opción costera más ligera suele ser más cómoda.","fitRouteLogicTitle":"Lógica del recorrido","fitRouteLogicSubtitle":"Ritmo, orden, tiempos en cada parada y por qué el día fluye así","practicalTitle":"Detalles prácticos","practicalSubtitle":"Recogida, caminata, clima, qué llevar e inclusiones.","seasonalTitle":"Estaciones del año","seasonalSubtitle":"Cómo se vive esta ruta a lo largo del año.","bookingSupportTitle":"Reserva y asistencia","bookingSupportSubtitle":"Qué esperar antes, durante y después.","bookingAfterTitle":"Tras reservar","bookingAfterSubtitle":"Apoyo que recibes antes, durante y después del tour","faqTitle":"Preguntas frecuentes","faqSubtitle":"Las dudas que suelen decidir si reservas o no.","faqShowFewer":"Ver menos","faqMoreQuestionsTemplate":"{count} preguntas más","faqFooterTitle":"¿Dudas antes de reservar?","faqFooterLink":"Escríbenos cuando quieras","reviewsTitle":"Opiniones de huéspedes","reviewsSubtitle":"Lo que dicen otros viajeros sobre la experiencia.","reviewsBasedOnTemplate":"Basado en {total} reseñas","reviewsGuestsMention":"Mencionan con frecuencia","reviewsShowFewerReviews":"Ver menos reseñas","reviewsShowAllTemplate":"Ver las {count} reseñas","reviewsVerified":"Verificada","reviewsReadMore":"Leer más","reviewsShowLess":"Mostrar menos","reviewsHelpfulTemplate":"Útil ({count})","reviewsCtaTitle":"¿Has hecho este tour?","reviewsCtaSubtitle":"Comparte tu experiencia para ayudar a otros viajeros.","reviewsWriteReview":"Escribir una reseña"},"hero":{"imageUrl":"https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=1920&q=80","imagePosition":"center 35%","tagline":"De la piedra al mar. Del cráter al jardín y la aldea.","pills":["Ideal para tu primera vez en Jeju","Este de Jeju"],"meta":{"duration":"8 h","region":"Este de Jeju","stops":"6 paradas","rating":4.8,"ratingStars":4}},"subnavItems":[{"id":"overview","label":"Resumen"},{"id":"itinerary","label":"Itinerario"},{"id":"details","label":"Detalles"},{"id":"faq","label":"Preguntas frecuentes"},{"id":"reviews","label":"Reseñas"}],"glanceItems":[{"icon":"camera","label":"Fotogenia","value":"Alta"},{"icon":"mountain","label":"Paisaje","value":"Alto"},{"icon":"footprints","label":"Caminata","value":"Moderada"},{"icon":"cloud-rain","label":"Apto con lluvia","value":"Medio"},{"icon":"users","label":"Para familias","value":"Bueno"},{"icon":"scale","label":"Ritmo","value":"Equilibrado"}],"galleryItems":[{"id":1,"type":"video","src":"https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=1200&q=80","location":"Vista general de la ruta","atmosphere":"Así se siente el día","alt":"Panorámica de la ruta costera del este de Jeju"},{"id":2,"type":"photo","src":"https://images.unsplash.com/photo-1548013146-72479768bada?w=800&q=80","location":"Inicio entre piedra y volcán","atmosphere":"Geología por la mañana","alt":"Esculturas de piedra en Jeju Stone Park"},{"id":3,"type":"photo","src":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=80","location":"Jardín y cueva de lava de Ilchulland","atmosphere":"Frescura y textura interior","alt":"Interior del jardín con cueva de lava en Ilchulland"},{"id":4,"type":"photo","src":"https://images.unsplash.com/photo-1590077428593-a55bb07c4665?w=800&q=80","location":"Textura de aldea tradicional","atmosphere":"Cultura con vida real","alt":"Aldea Folclórica de Seongeup"},{"id":5,"type":"photo","src":"https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=800&q=80","location":"Cráter frente al mar","atmosphere":"El gran momento del día","alt":"Cráter de Seongsan Ilchulbong"},{"id":6,"type":"video","src":"https://images.unsplash.com/photo-1469474968028-56623f02e42e?w=800&q=80","location":"Costa abierta y cresta junto al mar","atmosphere":"La parte más ligera y ventosa del recorrido","alt":"Sendero costero de Seopjikoji"}],"itineraryStops":[{"number":1,"time":"09:00","duration":"60 min","name":"Jeju Stone Park","category":"Geología y cultura de la piedra","description":"Aquí el día empieza a tener sentido. Stone Park presenta con claridad la identidad volcánica de Jeju y hace que, después, la costa, el cráter, la cueva de lava y la aldea tradicional se entiendan como parte de una misma historia.","image":"https://images.unsplash.com/photo-1548013146-72479768bada?w=800&q=80","highlights":["Esculturas de piedra, torres y amplios espacios abiertos","Excelente introducción a la cultura de la piedra en Jeju","Zonas muy limpias visualmente para hacer fotos","Elementos interiores de museo que profundizan el relato geológico"],"timeUsed":["Breve orientación por la zona principal de piedra","Tiempo para fotos y explicación en los campos de roca abiertos","Espacio de museo o interpretación final antes de salir"],"whyOnRoute":"Empezar aquí da contexto a todo lo que viene después: costa, cráter, lava y pueblo tradicional.","visitBasics":{"hours":"09:00-18:00","closed":"Lunes","admission":"Adultos 5.000 KRW / Adolescentes 3.500 KRW","walking":"Fácil a moderado"},"convenience":{"restroom":"Entrada y zona del museo","parking":"Disponible"},"smartNotes":{"photo":"Aquí funcionan mejor las composiciones amplias que los primeros planos cerrados.","facilities":"Es la parada con baños y apoyo interior más cómodos de la primera parte del recorrido.","tip":"Se disfruta más como una apertura tranquila que como una parada de fotos apresurada."}},{"number":2,"time":"10:40","duration":"60 min","name":"Seopjikoji","category":"Costa abierta sobre la cresta","description":"Después de Stone Park, el recorrido se abre hacia el mar. Seopjikoji aporta viento, línea de costa y vistas despejadas antes del almuerzo y prepara el ambiente para que Seongsan se sienta después como el gran hito volcánico del día.","image":"https://images.unsplash.com/photo-1469474968028-56623f02e42e?w=800&q=80","highlights":["Sendero costero abierto con vistas al mar","Campos florales de temporada según la época del año","Mirador del faro y panorámicas amplias del océano","Un contraste visual muy fresco frente a Stone Park"],"timeUsed":["Llegada y breve explicación de la ruta desde la entrada","Caminata principal por la zona de cresta y costa","Parada para fotos y regreso a ritmo relajado"],"whyOnRoute":"Abre primero la sensación de mar para que Seongsan llegue después con más fuerza como punto volcánico principal.","visitBasics":{"hours":"Abierto 24 horas","closed":"Ninguno","admission":"Gratis (parking aparte)","walking":"Fácil a moderado"},"convenience":{"restroom":"Zona de entrada","parking":"Parking de pago"},"smartNotes":{"photo":"Con viento y cielo abierto, suelen salir mejor las tomas laterales que las poses frontales estáticas.","facilities":"Pocas instalaciones; los baños están sobre todo en la entrada.","tip":"Aquí el viento y el sol se notan más que en la parada anterior."}},{"number":3,"time":"12:00","duration":"60 min","name":"Almuerzo","category":"Pausa de mediodía","description":"El almuerzo no es un simple descanso: es el punto que ordena el ritmo del día. Sirve para recuperar energía y llegar a Seongsan Ilchulbong, la actividad más fuerte de la jornada, con un ritmo mucho más cómodo.","image":"https://images.unsplash.com/photo-1590077428593-a55bb07c4665?w=800&q=80","highlights":["Recarga de energía antes de la parada más activa","Pausa natural entre la caminata costera y el cráter","Un ritmo más amable para grupos de edades mixtas","Ayuda a que la segunda mitad del día sea más fluida"],"timeUsed":["Llegada y acomodo en el restaurante","Comida y descanso breve","Preparación para salir hacia Seongsan"],"whyOnRoute":"Colocar el almuerzo aquí permite disfrutar Seongsan con más calma y menos sensación de prisa.","visitBasics":{"hours":"Horario del restaurante","closed":"Variable","admission":"Incluido o pago directo según la tarifa","walking":"Mínimo"},"convenience":{"restroom":"Instalaciones del restaurante","parking":"Disponible"},"smartNotes":{"photo":"Si te gusta la fotografía gastronómica, aquí conviene fijarse en los platos locales.","facilities":"Servicios completos de restaurante.","tip":"Aquí importa más recuperar bien el ritmo que ir rápido."}},{"number":4,"time":"13:15","duration":"90 min","name":"Seongsan Ilchulbong","category":"Cráter, caminata y cultura haenyeo","description":"Es el gran protagonista volcánico del día. Seongsan reúne paisaje de cráter, escala costera y, si el horario acompaña, el contexto del espectáculo de haenyeo, que añade una capa cultural muy propia de Jeju.","image":"https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=800&q=80","highlights":["Paisaje de cráter volcánico reconocido por la UNESCO","Vistas panorámicas muy potentes tanto desde la base como en altura","Geología costera icónica y silueta volcánica muy marcada","La referencia a las haenyeo aporta un valor cultural extra"],"timeUsed":["Llegada, orientación y organización en la entrada","Caminata principal ajustada al ritmo del grupo","Mirador del cráter o zona baja, y posible encaje con el horario del show de haenyeo"],"whyOnRoute":"Después del almuerzo, Seongsan funciona como el gran momento del día: activo, emblemático y muy Jeju.","visitBasics":{"hours":"07:00-20:00 (verano) / 07:30-19:00 (invierno)","closed":"Abierto todo el año","admission":"Adultos 5.000 KRW / Adolescentes 2.500 KRW","walking":"Exigente si se sube a la cima"},"convenience":{"restroom":"Base y zona cercana a la cima","parking":"Gran área de parking"},"smartNotes":{"photo":"Suelen funcionar mejor los encuadres amplios que incluyen cráter y línea de costa que las fotos centradas solo en la cima.","facilities":"Buenas instalaciones en la base; más básicas cerca de la parte alta.","tip":"El ritmo del grupo, el clima y la afluencia pueden hacer que la parada se incline más hacia caminata, miradores o espectáculo."}},{"number":5,"time":"15:00","duration":"55 min","name":"Ilchulland","category":"Jardín con cueva de lava","description":"Después de Seongsan, Ilchulland baja suavemente el pulso del día. Frente a la exposición al viento y la amplitud del cráter, aquí el ambiente se vuelve más fresco, más contenido y más sereno.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=80","highlights":["Ambiente de cueva de lava dentro de un recinto ajardinado","Un contraste muy agradable después de Seongsan","Caminos con sombra y un ritmo más suave","Buena transición entre el gran hito del día y el cierre"],"timeUsed":["Entrada al jardín y explicación del recorrido","Exploración principal de la cueva o del área temática interior","Breve cierre en el jardín y reagrupación"],"whyOnRoute":"Aquí funciona mejor como transición tranquila tras Seongsan, no como apertura principal del día.","visitBasics":{"hours":"09:00-18:00","closed":"Variable","admission":"Adultos 4.000 KRW / Adolescentes 2.000 KRW","walking":"Moderado"},"convenience":{"restroom":"En la entrada","parking":"Disponible"},"smartNotes":{"photo":"La mezcla de luz interior y exterior puede dar fotos con mucha atmósfera si se controla bien la exposición.","facilities":"Servicios básicos en la entrada.","tip":"Después de Seongsan suele sentirse especialmente cómodo por la sombra y el ritmo más contenido."}},{"number":6,"time":"16:20","duration":"40 min","name":"Aldea Folclórica de Seongeup","category":"Textura cultural de aldea","description":"Seongeup cierra el día desde la escala humana, no desde otro gran paisaje. Después de piedra, costa, cráter y cueva-jardín, la aldea añade historia viva, arquitectura tradicional y una sensación más terrenal de Jeju.","image":"https://images.unsplash.com/photo-1590077428593-a55bb07c4665?w=800&q=80","highlights":["Casas con techo de paja y muros de piedra tradicionales","Un final más cultural que puramente escénico","Ritmo tranquilo y mucha textura local","Excelente contraste frente a los grandes paisajes naturales previos"],"timeUsed":["Llegada y breve introducción histórica","Caminata por los puntos principales de la aldea","Explicación final y tiempo corto para mirar con calma"],"whyOnRoute":"Cerrar aquí hace que el día termine con más identidad local y no solo con una sucesión de paisajes icónicos.","visitBasics":{"hours":"Abierto durante el día","closed":"Ninguno","admission":"Gratis","walking":"Fácil, casi todo llano"},"convenience":{"restroom":"Centro de la aldea","parking":"Cerca"},"smartNotes":{"photo":"Aquí suelen funcionar mejor los tejados, callejones y texturas de piedra que los encuadres demasiado frontales.","facilities":"Servicios básicos de aldea.","tip":"Se disfruta más como un cierre breve pero sin prisa."}}],"routeFlowStops":[{"id":"01","name":"Stone Park","theme":"Piedra"},{"id":"02","name":"Seopjikoji","theme":"Costa"},{"id":"03","name":"Almuerzo","theme":"Pausa"},{"id":"04","name":"Seongsan","theme":"Cráter"},{"id":"05","name":"Ilchulland","theme":"Jardín"},{"id":"06","name":"Aldea","theme":"Cultura"}],"routePhases":[{"label":"Mañana","range":"1-2","theme":"De la piedra al mar","bgClass":"bg-sky-50/70","textClass":"text-sky-700","dotClass":"bg-sky-500"},{"label":"Mediodía","range":"3-4","theme":"Almuerzo y cráter","bgClass":"bg-amber-50/70","textClass":"text-amber-700","dotClass":"bg-amber-500"},{"label":"Cierre","range":"5-6","theme":"Jardín y aldea","bgClass":"bg-emerald-50/70","textClass":"text-emerald-700","dotClass":"bg-emerald-500"}],"routeShapeIntro":{"title":"Cómo fluye este día","subtitle":"De la piedra al mar, pausa al mediodía y luego cráter, jardín y aldea. De 09:00 a 17:00."},"whyTourWorks":{"bestFor":["Parejas en su primera visita a Jeju","Familias adultas","Viajeros que disfrutan entender el contexto del lugar","Seniors activos"],"lessIdeal":["Quienes quieren evitar por completo escaleras o cuevas","Grupos con mucho uso de cochecito","Niños muy pequeños"],"routeLogicSections":[{"title":"Ritmo y estructura","icon":"sun","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"Primero la piedra, antes del mar","detail":"Empezar en Stone Park le da sentido a lo que se verá después en la costa y en el paisaje volcánico."},{"label":"Almuerzo justo cuando hace falta","detail":"La pausa del mediodía llega en el momento ideal para resetear antes de Seongsan."},{"label":"El gran hito después de comer","detail":"Colocar Seongsan tras el almuerzo permite vivir la parte más intensa del día con mejor energía."}]},{"title":"Cómo se construye la ruta","icon":"mountain","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"Primero costa, luego cráter","detail":"Seopjikoji abre la sensación de mar y prepara el terreno para que Seongsan entre con más fuerza."},{"label":"Después del pico, un jardín para bajar el ritmo","detail":"Ilchulland suaviza muy bien la segunda mitad tras el momento más potente del día."},{"label":"El cierre lo pone la aldea, no otro mirador","detail":"Seongeup aporta una capa cultural y una sensación de vida local que redondean la jornada."}]},{"title":"Cuando cambian las condiciones","icon":"wind","iconBg":"bg-slate-50/80","iconColor":"text-slate-600","items":[{"label":"No opera los lunes","detail":"Esta ruta no sale los lunes."},{"label":"La costa y Seongsan son las partes más sensibles al clima","detail":"Seopjikoji y Seongsan son los dos puntos donde más se nota el viento y el tiempo."},{"label":"La carga de caminata puede ajustarse","detail":"En Seongsan se puede modular el ritmo según energía del grupo, clima y situación del lugar."}]}]},"practicalAccordionItems":[{"id":"pickup","title":"Recogida y regreso","preview":"Recogida en hoteles del área de Jeju City","content":["Recogida en el lobby del hotel entre 08:30 y 09:00","Regreso estimado entre 17:30 y 18:00","Recogida en aeropuerto disponible bajo consulta","La hora exacta se confirma la noche anterior"]},{"id":"walking","title":"Caminata y terreno","preview":"Nivel general moderado, manejable para la mayoría","content":["Caminata total aproximada: entre 4 y 6 km a lo largo del día","Stone Park: mayormente llano, con algunas superficies irregulares","Ilchulland: mezcla de senderos de jardín e interiores; algunas zonas pueden estar húmedas o algo irregulares","Seongsan Ilchulbong: subida opcional a la cima (~20 min) con pendiente pronunciada","Se recomiendan zapatos cómodos y con buen agarre"]},{"id":"weather","title":"Clima y ajustes operativos","preview":"Se realiza en la mayoría de condiciones, con ajustes si hace falta","content":["Lluvia ligera: el tour suele operar con normalidad","Lluvia fuerte: se puede acortar la exposición exterior y dar más protagonismo a Ilchulland","Viento fuerte: la estancia en Seopjikoji puede reducirse","Cierres puntuales: se podrán usar paradas alternativas cuando sea necesario"]},{"id":"wear","title":"Qué llevar y cómo vestirse","preview":"Calzado cómodo, capas ligeras y chaqueta fina","content":["Zapatos cómodos con buena tracción","Ropa en capas para cambios de temperatura","Chaqueta ligera cortaviento","Gorra y protector solar","Botella de agua"]},{"id":"included","title":"Incluye / no incluye","preview":"Guía, vehículo, recogida y entradas","variant":"included","content":["Guía profesional de habla inglesa","Vehículo privado o de grupo reducido","Recogida y regreso en hoteles de Jeju City","Todas las entradas","Agua embotellada","Almuerzo (pago directo en restaurante)","Compras personales","Propinas"]}],"practicalWeatherStatic":{"today":{"temp":"11°","label":"Hoy · Despejado"},"tomorrow":{"temp":"18°/13°","label":"Mañana · Llovizna"}},"seasonalVariations":[{"name":"Primavera","icon":"flower","description":"La costa se llena de amarillo con los campos de canola","tag":"Mejor época de flores","bgClass":"bg-spring","iconColor":"text-pink-500"},{"name":"Verano","icon":"sun","description":"Días largos y verdes intensos en toda la ruta","tag":"Más horas de luz","bgClass":"bg-summer","iconColor":"text-sky-500"},{"name":"Otoño","icon":"leaf","description":"Cielos limpios y visibilidad especialmente buena","tag":"Mejores vistas","bgClass":"bg-autumn","iconColor":"text-amber-600"},{"name":"Invierno","icon":"snow","description":"Menos gente y una atmósfera más tranquila","tag":"Ambiente sereno","bgClass":"bg-winter","iconColor":"text-slate-500"}],"bookingTrustItems":[{"icon":"check-circle","title":"Operador local con licencia","description":"Guiado con base en Jeju","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"Especialistas en la ruta del este","description":"Ritmo pensado para el este de Jeju","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"Grupo reducido","description":"Máximo 8 viajeros","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"Al reservar","title":"Confirmación inmediata","detail":"Recibes tu confirmación con resumen del itinerario"},{"timing":"12 horas antes","title":"Recordatorio previo","detail":"Actualización del clima y posibles ajustes"},{"timing":"La noche anterior","title":"Último aviso de recogida","detail":"Hora exacta y datos del conductor"},{"timing":"La mañana del tour","title":"Notas del día","detail":"Breve aviso según las condiciones reales"},{"timing":"Durante el tour","title":"Consejos parada por parada","detail":"Orientación útil en cada lugar"},{"timing":"Después del tour","title":"Soporte posterior","detail":"Sugerencias extra y seguimiento"}],"staticQuestions":[{"id":"first-time","question":"¿Es buena opción para una primera vez en Jeju?","answer":"Sí. Reúne la historia de la piedra y el volcán, la costa del este y varios de los puntos más representativos de Jeju en un recorrido muy equilibrado."},{"id":"walking","question":"¿Se camina mucho?","answer":"En general es un nivel manejable. La parte más exigente es la subida a la cima de Seongsan si decides hacerla; el resto del día se siente moderado para la mayoría."},{"id":"rain","question":"¿El tour sale aunque llueva?","answer":"Sí. En días de lluvia se ajusta con más cuidado la parte costera y puede darse más peso a Ilchulland, que funciona mejor con clima inestable."},{"id":"parents","question":"¿Puedo ir con mis padres?","answer":"Sí. Es una ruta cómoda para familias adultas y el ritmo puede ajustarse en las zonas más expuestas al viento."},{"id":"children","question":"¿Se puede hacer con niños?","answer":"Sí, aunque encaja mejor con niños de 8 años o más que estén cómodos con una jornada completa y caminata moderada."},{"id":"order","question":"¿Puede cambiar el orden de las paradas?","answer":"Sí. La costa depende del viento, el tráfico y el flujo de visitantes, así que puede haber pequeños cambios para que el día funcione mejor."},{"id":"lunch","question":"¿El almuerzo está incluido?","answer":"Depende de la tarifa reservada. El horario de almuerzo forma parte del recorrido, pero la inclusión de la comida puede variar según el producto."},{"id":"why-stone-park","question":"¿Por qué se empieza en Jeju Stone Park?","answer":"Porque permite abrir el día con calma y dar contexto a todo lo que viene después: costa, cráter, jardín y aldea."},{"id":"why-seopjikoji","question":"¿Por qué Seopjikoji va en la primera mitad?","answer":"Porque abre primero la atmósfera de mar y deja que Seongsan llegue después con más fuerza como gran hito volcánico."},{"id":"why-lunch","question":"¿Por qué el almuerzo está puesto ahí?","answer":"Porque ayuda a ordenar la energía del grupo justo antes de Seongsan, que es la parte más activa y potente del día."},{"id":"later-structure","question":"¿Por qué la segunda mitad está organizada así?","answer":"Después de Seongsan, Ilchulland baja el ritmo con un ambiente más fresco y contenido, y Seongeup cierra el día con una sensación más humana y cultural de Jeju."}],"guestReviews":[{"id":1,"author":"Sarah M.","avatar":"https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=100&q=80","location":"Singapur","date":"Marzo de 2024","rating":5,"title":"Un día perfectamente armado por el este de Jeju","text":"La ruta tenía muchísimo sentido. Empezar en Stone Park nos dio contexto para todo lo que vino después. El guía explicó la geología de una manera muy clara, así que Seongsan e Ilchulland no se sintieron como simples paradas para fotos. El almuerzo también cayó en el momento justo y todavía teníamos energía para disfrutar el cráter.","helpful":24,"verified":true,"tripType":"Pareja","photos":["https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=400&q=80","https://images.unsplash.com/photo-1469474968028-56623f02e42e?w=400&q=80"]},{"id":2,"author":"James K.","avatar":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=100&q=80","location":"Hong Kong","date":"Marzo de 2024","rating":5,"title":"La mejor forma de ver el este de Jeju en un solo día","text":"Hemos hecho varios tours en Corea y este destacó por lo bien pensado que estaba el orden. El guía sabía exactamente cuándo bajar el ritmo y cuándo avanzar. Terminar en la aldea folclórica fue un cierre cultural muy acertado después de tantos paisajes naturales.","helpful":18,"verified":true,"tripType":"Familia","photos":[]},{"id":3,"author":"Yuki T.","avatar":"https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=100&q=80","location":"Tokio","date":"Febrero de 2024","rating":4,"title":"Muy buena ruta; me habría gustado quedarme un poco más en Seongsan","text":"La experiencia general fue excelente. Stone Park me sorprendió para bien, e Ilchulland fue una pausa muy agradable después del cráter. Mi única pequeña pena fue que me habría gustado tener unos 15 minutos más en Seongsan, aunque entiendo perfectamente las limitaciones del horario.","helpful":12,"verified":true,"tripType":"Viaje en solitario","photos":["https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&q=80"]},{"id":4,"author":"Michael R.","avatar":"https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=100&q=80","location":"Sídney","date":"Febrero de 2024","rating":5,"title":"Superó mis expectativas","text":"Me apunté por los paisajes, pero lo que más me quedó fue la narrativa del día. El guía conectó cada parada con la siguiente y eso hizo que todo el recorrido se sintiera coherente. El almuerzo estuvo muy bien y, al ser un grupo pequeño, realmente podías escuchar y disfrutar las explicaciones.","helpful":31,"verified":true,"tripType":"Amigos","photos":[]}],"reviewsSummary":{"averageRating":4.8,"totalReviews":127,"ratingDistribution":[{"stars":5,"count":98,"percentage":77},{"stars":4,"count":21,"percentage":17},{"stars":3,"count":6,"percentage":5},{"stars":2,"count":1,"percentage":1},{"stars":1,"count":1,"percentage":1}],"highlights":[{"label":"Paisaje","count":89},{"label":"Guía","count":76},{"label":"Ritmo","count":54},{"label":"Puntos fotográficos","count":48}]}}'::jsonb
